import{_ as e,o as i,c as s,a3 as r}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Spécifications Techniques","description":"","frontmatter":{"title":"Spécifications Techniques"},"headers":[],"relativePath":"advertisers/sponsored-mail/design-guide/print-specs.md","filePath":"advertisers/sponsored-mail/design-guide/print-specs.md"}'),o={name:"advertisers/sponsored-mail/design-guide/print-specs.md"};function l(n,t,a,d,c,g){return i(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="specifications-techniques" tabindex="-1">Spécifications Techniques <a class="header-anchor" href="#specifications-techniques" aria-label="Permalink to &quot;Spécifications Techniques&quot;">​</a></h1><p>Les contraintes à respecter pour garantir une qualité d&#39;impression optimale et un tracking performant.</p><hr><h2 id="formats-papier" tabindex="-1">Formats Papier <a class="header-anchor" href="#formats-papier" aria-label="Permalink to &quot;Formats Papier&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Fini (découpé)</th><th style="text-align:left;">Fichier (avec fond perdu)</th><th style="text-align:left;">Zone tranquille</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>A5</strong></td><td style="text-align:left;">148 × 210 mm</td><td style="text-align:left;"><strong>152 × 214 mm</strong></td><td style="text-align:left;">3 mm internes</td></tr><tr><td style="text-align:left;"><strong>A6</strong></td><td style="text-align:left;">105 × 148 mm</td><td style="text-align:left;"><strong>109 × 152 mm</strong></td><td style="text-align:left;">3 mm internes</td></tr><tr><td style="text-align:left;"><strong>Carte</strong></td><td style="text-align:left;">105 × 148 mm</td><td style="text-align:left;"><strong>109 × 152 mm</strong></td><td style="text-align:left;">Voir gabarit</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Fond perdu (Bleed) : 2 mm obligatoire</p><p>La matière (image ou fond coloré) doit déborder de <strong>2 mm à l&#39;extérieur</strong> du format fini. Sans fond perdu, un liseré blanc apparaît après découpe.</p></div><div class="tip custom-block"><p class="custom-block-title">Zone tranquille : 3 mm</p><p>Aucun texte, logo ou élément important ne doit se trouver à moins de <strong>3 mm du bord intérieur</strong>. Ce qui est trop proche du bord risque d&#39;être rogné.</p></div><hr><h2 id="fichiers-colorimetrie" tabindex="-1">Fichiers &amp; Colorimétrie <a class="header-anchor" href="#fichiers-colorimetrie" aria-label="Permalink to &quot;Fichiers &amp; Colorimétrie&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Critère</th><th style="text-align:left;">Spécification</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Format de fichier</strong></td><td style="text-align:left;">PDF/X (vectoriel) — à privilégier. JPG ou PNG acceptés.</td></tr><tr><td style="text-align:left;"><strong>Résolution</strong></td><td style="text-align:left;"><strong>300 DPI minimum</strong></td></tr><tr><td style="text-align:left;"><strong>Mode colorimétrique</strong></td><td style="text-align:left;"><strong>CMJN obligatoire</strong> (pas de RVB)</td></tr><tr><td style="text-align:left;"><strong>Profil ICC</strong></td><td style="text-align:left;">Coated FOGRA39</td></tr><tr><td style="text-align:left;"><strong>Taux d&#39;encrage</strong></td><td style="text-align:left;"><strong>Maximum 300%</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Astuce — Noir Profond</p><p>Pour un noir riche sur les aplats (fonds noirs larges) : utilisez <strong>C30% M30% J30% N100%</strong>. Pour les textes fins et petits caractères : utilisez <strong>N100% seul</strong> pour éviter le décalage à l&#39;impression.</p></div><hr><h2 id="papier" tabindex="-1">Papier <a class="header-anchor" href="#papier" aria-label="Permalink to &quot;Papier&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Spécifications papier recommandées</p><ul><li><strong>Grammage :</strong> 250 à 300 g/m²</li><li><strong>Type :</strong> Couché mat ou couché demi-mat</li><li><strong>Certification :</strong> FSC ou PEFC</li><li><strong>Pelliculage :</strong> Non — le pelliculage rend les QR codes moins lisibles</li></ul></div><hr><h2 id="qr-code-getinside" tabindex="-1">QR Code getinside <a class="header-anchor" href="#qr-code-getinside" aria-label="Permalink to &quot;QR Code getinside&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">QR code propriétaire obligatoire</p><p>Vous <strong>ne pouvez pas</strong> utiliser un QR code généré par vos soins. Vous devez impérativement intégrer le fichier <strong><code>.svg</code></strong> fourni par la plateforme getinside.</p><p><strong>Pourquoi ?</strong> Ce QR code unique certifie la distribution, permet le monitoring en temps réel et active votre tableau de bord de performance.</p></div><p><strong>Taille minimum : 25 × 25 mm</strong> (en dessous, le QR code n&#39;est pas lisible par tous les smartphones).</p><div class="gi-value-grid"><div class="gi-value-card"><strong>✨ QR Code Dynamique</strong><p>L&#39;URL de destination n&#39;est pas gravée dans le motif du code.</p><p>Vous pouvez modifier la landing page à tout moment depuis la plateforme — <strong>même après l&#39;impression des flyers</strong>. Idéal pour corriger une erreur d&#39;URL ou prolonger une offre.</p></div><div class="gi-value-card"><strong>🎯 Tracking &amp; UTM</strong><p>getinside mesure les scans. Pour suivre les <strong>ventes</strong> dans Google Analytics, configurez l&#39;URL avec des paramètres UTM :</p><p><code>monsite.com?utm_source=getinside&amp;utm_medium=insertion-colis&amp;utm_campaign=printemps</code></p><p>Ajoutez aussi un <strong>code promo unique</strong> par distributeur pour l&#39;attribution offline.</p></div></div><hr><h2 id="formats-echantillons-sampling" tabindex="-1">Formats Échantillons (Sampling) <a class="header-anchor" href="#formats-echantillons-sampling" aria-label="Permalink to &quot;Formats Échantillons (Sampling)&quot;">​</a></h2><p>getinside permet la distribution d&#39;échantillons seuls ou assemblés avec un flyer.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Poids max</th><th style="text-align:left;">Développé max (H + l + L)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Format S</strong></td><td style="text-align:left;">15 g</td><td style="text-align:left;">15 cm</td></tr><tr><td style="text-align:left;"><strong>Format M</strong></td><td style="text-align:left;">100 g</td><td style="text-align:left;">30 cm</td></tr><tr><td style="text-align:left;"><strong>Format L</strong></td><td style="text-align:left;">450 g</td><td style="text-align:left;">40 cm</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Option &quot;Duo&quot; — Assemblage Flyer + Échantillon (Format S)</p><p>L&#39;échantillon est collé sur un flyer A5 ou A6 via un point de <strong>colle fugitive</strong> (repositionnable), permettant de le détacher sans abîmer le flyer.</p><p>Cette prestation est réalisée par des <strong>Entreprises Adaptées (EA)</strong>, favorisant l&#39;emploi de travailleurs handicapés.</p></div><hr><h2 id="checklist-bat" tabindex="-1">Checklist BAT <a class="header-anchor" href="#checklist-bat" aria-label="Permalink to &quot;Checklist BAT&quot;">​</a></h2><p>À vérifier avant chaque soumission :</p><ol><li>Les dimensions incluent <strong>+2 mm de fond perdu</strong> et respectent <strong>-3 mm de zone tranquille</strong>.</li><li>Le fichier est en <strong>CMJN (FOGRA39)</strong>, résolution ≥ <strong>300 DPI</strong>, taux d&#39;encrage ≤ <strong>300%</strong>.</li><li>Le QR code getinside (<code>.svg</code>) est présent et mesure au minimum <strong>25 × 25 mm</strong>.</li><li>Les mentions légales universelles sont incluses : identification annonceur, Triman, logo getinside, CGV.</li><li>Les mentions sectorielles obligatoires (si applicable) sont lisibles.</li></ol><p>→ <a href="https://docs.google.com/document/d/17oybJkf4iOX0XrC4LOJSI0zp2y0w_Wn7F4GW_oBAZcM/edit" target="_blank">Télécharger la Check-list complète</a></p>',29)])])}const u=e(o,[["render",l]]);export{m as __pageData,u as default};
